import{_ as s,o as t,c as n,ag as o}from"./chunks/framework.DZKik_R9.js";const u=JSON.parse('{"title":"Segments","description":"","frontmatter":{},"headers":[],"relativePath":"solution/campaigns-segments/segments.md","filePath":"solution/campaigns-segments/segments.md"}'),i={name:"solution/campaigns-segments/segments.md"};function a(r,e,l,d,c,p){return t(),n("div",null,[...e[0]||(e[0]=[o(`<h1 id="segments" tabindex="-1">Segments <a class="header-anchor" href="#segments" aria-label="Permalink to &quot;Segments&quot;">​</a></h1><h2 id="role" tabindex="-1">Rôle <a class="header-anchor" href="#role" aria-label="Permalink to &quot;Rôle&quot;">​</a></h2><p>Un <strong>segment</strong> décrit un <strong>ensemble d’utilisateurs</strong> (ou de contextes) auquel on peut rattacher une campagne. Les règles s’évaluent contre un <strong><code>UserContext</code></strong> fourni à <code>/api/evaluate</code>.</p><h2 id="lien-avec-une-campagne" tabindex="-1">Lien avec une campagne <a class="header-anchor" href="#lien-avec-une-campagne" aria-label="Permalink to &quot;Lien avec une campagne&quot;">​</a></h2><p>Dans le <code>config.json</code> d’une <strong><a href="./campaigns">campagne</a></strong>, le champ <strong><code>segments</code></strong> est un tableau d’<strong>ids numériques</strong> qui pointent vers des entrées sous <code>Segments/</code> (même valeur que le champ <code>id</code> de chaque segment). <strong><code>[]</code></strong> signifie qu’aucun segment n’est requis pour l’éligibilité : le moteur ne filtre pas sur des règles de segment pour cette campagne.</p><p>Si la liste est <strong>non vide</strong>, l’utilisateur doit satisfaire <strong>au moins un</strong> des segments listés (chacun est évalué via une <strong>condition</strong> booléenne, en général un arbre <strong>ET / OU</strong> ; la campagne reste éligible dès qu’<strong>un</strong> segment du tableau matche le contexte).</p><p>Pour un <strong>diagnostic critère par critère</strong> (valeur attendue vs valeur actuelle dans un <code>UserContext</code> de test), le mode simulation côté API expose <code>POST /api/evaluate/segment-diagnostics</code> — voir <a href="./../../reference/api-overview">Aperçu de l’API</a>. L’interface d’administration peut l’utiliser pour la prévisualisation ; ce n’est pas le chemin nominal d’assignation de variante.</p><h2 id="arborescence-dans-le-depot" tabindex="-1">Arborescence dans le dépôt <a class="header-anchor" href="#arborescence-dans-le-depot" aria-label="Permalink to &quot;Arborescence dans le dépôt&quot;">​</a></h2><p>Sous <strong><code>abtest-campaigns-segments/Segments/</code></strong>, chaque segment est en général un dossier :</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Segments/</span></span>
<span class="line"><span>  VisitorsTablet_FR/</span></span>
<span class="line"><span>    config.json</span></span>
<span class="line"><span>  ...</span></span></code></pre></div><p>Chaque <strong><code>config.json</code></strong> contient au minimum <code>id</code> et <code>name</code>, souvent <code>description</code>, et les règles de ciblage. Le champ <strong><code>id</code></strong> est un <strong>nombre entier</strong> dans la plage <strong>1000–9999</strong> (type JSON <code>number</code>).</p><h2 id="fichier-config-json" tabindex="-1">Fichier <code>config.json</code> <a class="header-anchor" href="#fichier-config-json" aria-label="Permalink to &quot;Fichier \`config.json\`&quot;">​</a></h2><h3 id="format-condition-et-ou-non" tabindex="-1">Format <code>condition</code> (ET / OU / NON) <a class="header-anchor" href="#format-condition-et-ou-non" aria-label="Permalink to &quot;Format \`condition\` (ET / OU / NON)&quot;">​</a></h3><p>Arbre booléen exposé par le moteur après normalisation :</p><ul><li><strong><code>allOf</code></strong> — tableau <strong><code>conditions</code></strong> : <strong>toutes</strong> les sous-conditions doivent être vraies (<strong>ET</strong>). Tableau vide → segment <strong>universel</strong> (toujours vrai).</li><li><strong><code>anyOf</code></strong> — tableau <strong><code>conditions</code></strong> : <strong>au moins une</strong> sous-condition doit être vraie (<strong>OU</strong>). Tableau vide → <strong>jamais</strong> vrai.</li><li><strong><code>not</code></strong> — une seule sous-clé <strong><code>condition</code></strong> : le résultat est l’inverse de cette sous-condition (<strong>NON</strong>).</li></ul><p>Chaque élément de <code>conditions</code> est soit une <strong>règle feuille</strong> (objet avec <code>type</code> = pays, URL, etc., voir <a href="./segment-types">Types de segment</a>), soit un autre nœud <code>allOf</code> / <code>anyOf</code> / <code>not</code>. Tu peux <strong>imbriquer</strong> librement (ex. <strong>(A OU B) ET C</strong> = un <code>allOf</code> dont le premier enfant est un <code>anyOf</code> sur A et B, le second est C).</p><p>D’autres <strong>exemples JSON</strong> (tableau récapitulatif, OU sur pays, <strong>NON</strong> combiné avec <strong>ET</strong>) sont sur la page <a href="./segment-conditions">Conditions de segment</a>.</p><p>Dans un même <strong><code>config.json</code></strong>, il faut <strong>exactement un</strong> des deux : soit <strong><code>condition</code></strong>, soit <strong><code>rules</code></strong> (pas les deux, pas l’absence des deux). Sinon la validation <strong><code>storage-fs</code></strong> rejette le fichier.</p><p>Après chargement, l’API (<code>GET /api/segments</code>, etc.) renvoie toujours le segment avec le champ <strong><code>condition</code></strong> (forme normalisée interne), y compris quand le fichier ne contient que <strong><code>rules</code></strong>.</p><h3 id="rules-liste-plate-et" tabindex="-1"><code>rules</code> (liste plate = ET) <a class="header-anchor" href="#rules-liste-plate-et" aria-label="Permalink to &quot;\`rules\` (liste plate = ET)&quot;">​</a></h3><p>Tableau de règles feuilles, équivalent à <code>{ &quot;type&quot;: &quot;allOf&quot;, &quot;conditions&quot;: [ … ] }</code>. Un tableau vide <strong><code>[]</code></strong> signifie « tous les utilisateurs » (segment universel).</p><p>Exemple minimal :</p><div class="language-json vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">json</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;id&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">3842</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;name&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;Tous les utilisateurs&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;description&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;Segment par défaut qui matche tout le monde.&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;rules&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: []</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><p>Exemple avec une règle pays :</p><div class="language-json vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">json</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;id&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">9156</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;name&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;France uniquement&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;description&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;Cible uniquement les utilisateurs dont le pays est FR.&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;rules&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: [{ </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">&quot;type&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;country&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">&quot;operator&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;isAnyOf&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">&quot;values&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: [</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;FR&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">] }]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><p>L’équivalent d’un ancien bloc <strong><code>criteria</code></strong> (pays / device / <code>loggedIn</code>) s’exprime en <strong><code>rules</code></strong> (voir <a href="./segment-types">Types de segment</a>) — par exemple pays FR <strong>et</strong> mobile <strong>et</strong> connecté : trois entrées dans le tableau <code>rules</code>, combinées en <strong>ET</strong>.</p><p>Pour des <strong>exemples JSON</strong> d’arbres <strong><code>condition</code></strong> (OU sur pays, combinaisons <strong>(A OU B) ET C</strong>, <strong>not</strong>), voir <strong><a href="./segment-conditions">Conditions de segment</a></strong>.</p><h2 id="contexte-usercontext" tabindex="-1">Contexte (<code>UserContext</code>) <a class="header-anchor" href="#contexte-usercontext" aria-label="Permalink to &quot;Contexte (\`UserContext\`)&quot;">​</a></h2><p>Champs utiles côté moteur (<code>@abtest-solution/core</code>) :</p><p><code>route</code>, <code>url</code>, <code>queryParams</code>, <code>country</code> (souvent GeoIP), <code>region</code>, <code>city</code>, <code>device</code>, <code>screenWidth</code> / <code>screenHeight</code>, <code>browser</code>, <code>browserVersion</code>, <code>browserLanguage</code>, <code>cookies</code>, <code>visitorType</code> (<code>new</code> | <code>returning</code>), <code>domPresence</code>, <code>customRuleResults</code>.</p><ul><li>Le <strong>remote</strong> (<code>buildBrowserEvaluateContext</code>) remplit la partie <strong>navigateur</strong> (dont <code>visitorType</code> via un cookie démo du type <code>abtest_returning</code>).</li><li><strong><code>country</code> / <code>region</code> / <code>city</code></strong> : en production, souvent injectés par un <strong>BFF</strong>, <strong>edge</strong> ou <strong>CDN</strong> avant l’appel à <code>/api/evaluate</code>, si tu ne te limites pas au seul contexte client.</li></ul><h2 id="types-de-regles-feuilles" tabindex="-1">Types de règles (feuilles) <a class="header-anchor" href="#types-de-regles-feuilles" aria-label="Permalink to &quot;Types de règles (feuilles)&quot;">​</a></h2><p>Chaque règle feuille est un objet JSON avec <strong><code>type</code></strong>, <strong><code>operator</code></strong> (sauf cas sans opérateur), et les champs attendus par le moteur. En liste <strong><code>rules</code></strong>, elles sont reliées par un <strong>ET</strong> ; avec <strong><code>condition</code></strong>, l’ET / OU / NON est explicite.</p><p>La <strong>référence des règles feuilles</strong> (tous les <code>type</code>, opérateurs, paramètres) est sur <strong><a href="./segment-types">Types de segment</a></strong>. Pour l’arbre <strong><code>condition</code></strong> (ET / OU / NON, exemples), voir <strong><a href="./segment-conditions">Conditions de segment</a></strong>.</p><h2 id="voir-aussi" tabindex="-1">Voir aussi <a class="header-anchor" href="#voir-aussi" aria-label="Permalink to &quot;Voir aussi&quot;">​</a></h2><ul><li><a href="./scaffold-cli">CLI : squelettes (IDE)</a> — créer un segment depuis l’IDE avec id libre</li><li><a href="./segment-conditions">Conditions de segment</a> — arbre <code>condition</code>, exemples JSON</li><li><a href="./segment-types">Types de segment</a> — catalogue des <code>type</code> / <code>operator</code> / JSON</li><li><a href="./campaigns">Campagnes</a></li><li><a href="./../consent">Consentement</a> — cookies dans le contexte</li><li><a href="./../module-federation">Module Federation</a></li></ul>`,36)])])}const h=s(i,[["render",a]]);export{u as __pageData,h as default};
